@* Displays a single task with title, assignee, priority badge, due date, and move buttons *@

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <span class="badge @PriorityClass me-1">@Task.Priority</span>
        <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        <div class="mt-2 d-flex justify-content-between">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@* Inline form to create a new task within a column *@

<div class="card mb-2 border-primary">
    <div class="card-body p-2">
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Title" @bind="Title" />
        </div>
        <div class="mb-2">
            <input type="text" class="form-control form-control-sm" placeholder="Assignee" @bind="Assignee" />
        </div>
        <div class="mb-2">
            <select class="form-select form-select-sm" @bind="Priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="mb-2">
            <input type="date" class="form-control form-control-sm" @bind="DueDate" />
        </div>
        <div class="d-flex gap-1">
            <button class="btn btn-primary btn-sm" @onclick="HandleSave" disabled="@IsSaving">
                @(IsSaving ? "Saving..." : "Save")
            </button>
            <button class="btn btn-secondary btn-sm" @onclick="OnCancel" disabled="@IsSaving">Cancel</button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnSave { get; set; }
    [Parameter, EditorRequired] public EventCallback OnCancel { get; set; }

    private string Title { get; set; } = "";
    private string Assignee { get; set; } = "";
    private string Priority { get; set; } = "Medium";
    private DateTime DueDate { get; set; } = DateTime.Today.AddDays(7);
    private bool IsSaving { get; set; }

    private async Task HandleSave()
    {
        if (string.IsNullOrWhiteSpace(Title)) return;
        IsSaving = true;
        await OnSave.InvokeAsync((Title, Assignee, Priority, DueDate));
        IsSaving = false;
    }
}

@* A single Kanban column: header with count, task cards, and add-task toggle *@

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body p-2" style="overflow-y: auto;">
            @foreach (var task in Tasks)
            {
                <BoardTaskCard Task="task"
                               CanMoveLeft="CanMoveLeft"
                               CanMoveRight="CanMoveRight"
                               OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, LeftStatus!))"
                               OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, RightStatus!))" />
            }

            @if (_showForm)
            {
                <BoardAddTaskForm OnSave="HandleSave" OnCancel="() => _showForm = false" />
            }
            else
            {
                <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => _showForm = true">+ Add Task</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = "";
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public string? LeftStatus { get; set; }
    [Parameter] public string? RightStatus { get; set; }
    [Parameter] public EventCallback<(int TaskId, string NewStatus)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnAddTask { get; set; }

    private bool CanMoveLeft => LeftStatus is not null;
    private bool CanMoveRight => RightStatus is not null;
    private bool _showForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnAddTask.InvokeAsync(data);
        _showForm = false;
    }
}

@* Search input that filters tasks by title *@

<div class="mb-3">
    <input type="text"
           class="form-control"
           placeholder="Search tasks by title..."
           value="@SearchTerm"
           @oninput="HandleInput" />
</div>

@code {
    [Parameter] public string SearchTerm { get; set; } = "";
    [Parameter] public EventCallback<string> SearchTermChanged { get; set; }

    private async Task HandleInput(ChangeEventArgs e)
    {
        var value = e.Value?.ToString() ?? "";
        await SearchTermChanged.InvokeAsync(value);
    }
}

@page "/board"
@using sv_46a307071ef4401d8fda9cbabd83923f
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Kanban Board</h3>

@if (_loading)
{
    <div class="d-flex justify-content-center my-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @_error
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="_tasks" />
    <BoardSearchBar @bind-SearchTerm="_searchTerm" />

    <div class="row g-3">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetFiltered("To Do")"
                     RightStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask("To Do", args)" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetFiltered("In Progress")"
                     LeftStatus="To Do"
                     RightStatus="Done"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask("In Progress", args)" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetFiltered("Done")"
                     LeftStatus="In Progress"
                     OnMoveTask="HandleMoveTask"
                     OnAddTask="args => HandleAddTask("Done", args)" />
    </div>
}

@code {
    private List<TaskItem> _tasks = new();
    private string _searchTerm = "";
    private bool _loading = true;
    private string? _error;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        _loading = true;
        _error = null;
        try
        {
            _tasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    private List<TaskItem> GetFiltered(string status)
    {
        var query = _tasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(_searchTerm))
        {
            query = query.Where(t => t.Title.Contains(_searchTerm, StringComparison.OrdinalIgnoreCase));
        }
        return query.ToList();
    }

    private async Task HandleMoveTask((int TaskId, string NewStatus) args)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(args.TaskId, args.NewStatus);
            var idx = _tasks.FindIndex(t => t.Id == args.TaskId);
            if (idx >= 0)
            {
                var old = _tasks[idx];
                _tasks[idx] = old with { Status = args.NewStatus };
            }
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }

    private async Task HandleAddTask(string status, (string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
            _tasks.Add(created);
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
    }
}

